// --- player.h ---
#ifndef PLAYER_H
#define PLAYER_H

#include <string>

class Player {
private:
    std::string name;
    int health;
    int attack;
    int defense;
    int level;

public:
    Player(const std::string& n);
    void setHealth(int h);
    int getHealth() const;
    void setAttack(int a);
    int getAttack() const;
    void setDefense(int d);
    int getDefense() const;
    void levelUp();
    void display() const;
    std::string getName() const;
};

#endif

// --- player.cpp ---
#include "player.h"
#include <iostream>

Player::Player(const std::string& n) : name(n), health(100), attack(15), defense(10), level(1) {
    std::cout << "Player " << name << " created!" << std::endl;
}

void Player::setHealth(int h) { health = h; }
int Player::getHealth() const { return health; }
void Player::setAttack(int a) { attack = a; }
int Player::getAttack() const { return attack; }
void Player::setDefense(int d) { defense = d; }
int Player::getDefense() const { return defense; }

void Player::levelUp() {
    level++;
    health += 20;
    attack += 5;
    defense += 3;
    std::cout << name << " leveled up to level " << level << "!" << std::endl;
}

void Player::display() const {
    std::cout << "\n=== Player: " << name << " ===" << std::endl;
    std::cout << "Level: " << level << std::endl;
    std::cout << "Health: " << health << std::endl;
    std::cout << "Attack: " << attack << std::endl;
    std::cout << "Defense: " << defense << std::endl;
}

std::string Player::getName() const { return name; }

// --- enemy.h ---
#ifndef ENEMY_H
#define ENEMY_H

#include <string>

class Enemy {
private:
    std::string name;
    int health;
    int attack;
    bool isBoss;

public:
    Enemy(const std::string& n, int h, int a, bool boss = false);
    void takeDamage(int damage);
    int getAttack() const;
    int getHealth() const;
    bool isAlive() const;
    void display() const;
    std::string getName() const;
};

#endif

// --- enemy.cpp ---
#include "enemy.h"
#include <iostream>

Enemy::Enemy(const std::string& n, int h, int a, bool boss) 
    : name(n), health(h), attack(a), isBoss(boss) {
    std::cout << "Enemy " << name << (isBoss ? " (BOSS)" : "") << " spawned!" << std::endl;
}

void Enemy::takeDamage(int damage) {
    health -= damage;
    if (health < 0) health = 0;
    std::cout << name << " took " << damage << " damage!" << std::endl;
}

int Enemy::getAttack() const { return attack; }
int Enemy::getHealth() const { return health; }
bool Enemy::isAlive() const { return health > 0; }

void Enemy::display() const {
    std::cout << "Enemy: " << name 
              << " (HP: " << health 
              << ", ATK: " << attack 
              << ", " << (isBoss ? "BOSS" : "Normal") << ")" << std::endl;
}

std::string Enemy::getName() const { return name; }

// --- combat.h ---
#ifndef COMBAT_H
#define COMBAT_H

#include "player.h"
#include "enemy.h"

void fight(Player& player, Enemy& enemy);
int calculateDamage(int attack, int defense);

#endif

// --- combat.cpp ---
#include "combat.h"
#include <iostream>

int calculateDamage(int attack, int defense) {
    int damage = attack - (defense / 2);
    return damage > 0 ? damage : 1;
}

void fight(Player& player, Enemy& enemy) {
    std::cout << "\n=== FIGHT! ===" << std::endl;
    std::cout << player.getName() << " vs " << enemy.getName() << std::endl;

    while (player.getHealth() > 0 && enemy.isAlive()) {
        int damage = calculateDamage(player.getAttack(), enemy.getAttack());
        enemy.takeDamage(damage);

        if (enemy.isAlive()) {
            damage = calculateDamage(enemy.getAttack(), player.getDefense());
            player.setHealth(player.getHealth() - damage);
            std::cout << player.getName() << " took " << damage << " damage!" << std::endl;
        }
    }

    if (player.getHealth() > 0) {
        std::cout << "\n" << player.getName() << " wins!" << std::endl;
        player.levelUp();
    } else {
        std::cout << "\n" << enemy.getName() << " wins!" << std::endl;
    }
}

// --- main.cpp ---
#include "player.h"
#include "enemy.h"
#include "combat.h"
#include <iostream>

int main() {
    std::cout << "=== Multi-file Game Project ===" << std::endl;

    Player hero("Hero");
    Enemy goblin("Goblin", 40, 8);

    hero.display();
    goblin.display();

    fight(hero, goblin);

    hero.display();

    std::cout << "\n✅ Project structure complete!" << std::endl;

    return 0;
}

