#define PLAYER_H

class Player {
    // Implementation in header (BAD!)
    void display() {
        std::cout << "Display" << std::endl;
    }
};

#endif

// --- main.cpp ---
#include "player.h"

int main() {
    Player p;
    p.display();
    return 0;
