// --- game.h (Header) ---
#ifndef GAME_H
#define GAME_H

#include <string>

class Game {
private:
    std::string title;
    int version;

public:
    Game(const std::string& t, int v);
    void display() const;
    std::string getTitle() const;
    int getVersion() const;
};

#endif

// --- game.cpp (Implementation) ---
#include "game.h"
#include <iostream>

Game::Game(const std::string& t, int v) : title(t), version(v) {
    std::cout << "Game created: " << title << " v" << version << std::endl;
}

void Game::display() const {
    std::cout << "=== Game ===" << std::endl;
    std::cout << "Title: " << title << std::endl;
    std::cout << "Version: " << version << std::endl;
}

std::string Game::getTitle() const { return title; }
int Game::getVersion() const { return version; }

// --- main.cpp (Main) ---
#include "game.h"
#include <iostream>

int main() {
    std::cout << "=== Multi-file Project ===" << std::endl;

    Game myGame("Adventure Quest", 2);
    myGame.display();

    return 0;
}
